// Build seller_name → seller_id map from the fetched sellers
const sellers = $input.all();
const sellerMap = {};
for (const row of sellers) {
  sellerMap[row.json.seller_name] = row.json.seller_id;
}
// Return a single item carrying the map + the list of brand slugs from index
return [{ json: { sellerMap, sellerCount: Object.keys(sellerMap).length } }];

// Transform brand's products into seller_products payload
// Must resolve seller_id from the sellerMap built earlier
const brandPayload = $input.first().json;
const sellerMap = $('Build seller name → UUID map').first().json.sellerMap;

const sellerId = sellerMap[brandPayload.brand_name];
if (!sellerId) {
  console.log(`⚠️ No seller_id found for ${brandPayload.brand_name}, skipping`);
  return [];
}

const rows = (brandPayload.products || []).map(p => ({
  seller_id: sellerId,
  product_name: (p.title || '').slice(0, 500),
  category: p.product_type || null,
  avg_price: (p.price_min != null && p.price_max != null) ? Math.round((p.price_min + p.price_max) / 2) : (p.price_min || p.price_max || null),
  min_price: p.price_min ?? null,
  max_price: p.price_max ?? null,
  product_id_shopify: p.id ? String(p.id) : null,
  handle: p.handle || null,
  tags: Array.isArray(p.tags) ? p.tags : null,
  available: p.available ?? null,
  vendor: p.vendor || null,
  url: p.url || null
}));

// Split rows into batches of 500 for efficient POST
const BATCH = 500;
const batches = [];
for (let i = 0; i < rows.length; i += BATCH) {
  batches.push({ json: { brand_name: brandPayload.brand_name, batch: rows.slice(i, i + BATCH) } });
}
return batches;
